import { useQuery, useAction } from 'wasp/client/operations'
import { getTasks } from 'wasp/server/operations'
import { createTask, createLabel, addLabelToTask } from 'wasp/server/operations'
import { useState } from 'react'
import './Main.css'

type Task = {
  id: number
  description: string
  labels: Label[]
}

type Label = {
  id: number
  name: string
  tasks: Task[]
}

export function MainPage() {
  const { data: tasks, refetch } = useQuery(getTasks)
  const createTaskFn = useAction(createTask)
  const createLabelFn = useAction(createLabel)
  const addLabelToTaskFn = useAction(addLabelToTask)

  const [taskDescription, setTaskDescription] = useState('')
  const [labelName, setLabelName] = useState('')
  const [selectedTaskId, setSelectedTaskId] = useState<number | null>(null)
  const [selectedLabelId, setSelectedLabelId] = useState<number | null>(null)

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!taskDescription.trim()) return
    await createTaskFn({ description: taskDescription })
    setTaskDescription('')
    refetch()
  }

  const handleCreateLabel = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!labelName.trim()) return
    await createLabelFn({ name: labelName })
    setLabelName('')
    refetch()
  }

  const handleAddLabelToTask = async () => {
    if (selectedTaskId === null || selectedLabelId === null) return
    await addLabelToTaskFn({ taskId: selectedTaskId, labelId: selectedLabelId })
    setSelectedTaskId(null)
    setSelectedLabelId(null)
    refetch()
  }

  const allLabels = tasks
    ? tasks.flatMap((task) => task.labels)
    : []
  const uniqueLabels = Array.from(
    new Map(allLabels.map((label) => [label.id, label])).values()
  )

  return (
    <main className="container">
      <h1 className="title">Task Labels Manager</h1>

      <div className="forms-section">
        <form className="form" onSubmit={handleCreateTask}>
          <h3>Create Task</h3>
          <input
            type="text"
            value={taskDescription}
            onChange={(e) => setTaskDescription(e.target.value)}
            placeholder="Enter task description"
            className="input"
          />
          <button type="submit" className="button button-filled">
            Create Task
          </button>
        </form>

        <form className="form" onSubmit={handleCreateLabel}>
          <h3>Create Label</h3>
          <input
            type="text"
            value={labelName}
            onChange={(e) => setLabelName(e.target.value)}
            placeholder="Enter label name"
            className="input"
          />
          <button type="submit" className="button button-filled">
            Create Label
          </button>
        </form>
      </div>

      <div className="add-label-section">
        <h3>Add Label to Task</h3>
        <div className="add-label-controls">
          <select
            value={selectedTaskId || ''}
            onChange={(e) => setSelectedTaskId(Number(e.target.value))}
            className="input"
          >
            <option value="">Select a task</option>
            {tasks?.map((task) => (
              <option key={task.id} value={task.id}>
                {task.description}
              </option>
            ))}
          </select>

          <select
            value={selectedLabelId || ''}
            onChange={(e) => setSelectedLabelId(Number(e.target.value))}
            className="input"
          >
            <option value="">Select a label</option>
            {uniqueLabels.map((label) => (
              <option key={label.id} value={label.id}>
                {label.name}
              </option>
            ))}
          </select>

          <button
            onClick={handleAddLabelToTask}
            className="button button-filled"
            disabled={selectedTaskId === null || selectedLabelId === null}
          >
            Add Label
          </button>
        </div>
      </div>

      <div className="tasks-section">
        <h2>Tasks</h2>
        {tasks && tasks.length > 0 ? (
          <ul className="task-list">
            {tasks.map((task) => (
              <li key={task.id} className="task-item">
                <div className="task-description">{task.description}</div>
                {task.labels.length > 0 ? (
                  <div className="task-labels">
                    Labels:
                    {task.labels.map((label) => (
                      <span key={label.id} className="label-badge">
                        {label.name}
                      </span>
                    ))}
                  </div>
                ) : (
                  <div className="no-labels">No labels</div>
                )}
              </li>
            ))}
          </ul>
        ) : (
          <p className="no-tasks">No tasks yet. Create one above!</p>
        )}
      </div>
    </main>
  )
}

